+
+const { ContainerServiceFleetClient } = require("@azure/arm-containerservicefleet");
+const { DefaultAzureCredential } = require("@azure/identity");
+
+/**
+ * This sample demonstrates how to create a FleetManagedNamespace
+ *
+ * @summary create a FleetManagedNamespace
+ * x-ms-original-file: 2026-02-01-preview/FleetManagedNamespaces_CreateOrUpdate.json
+ */
+async function fleetManagedNamespacesCreateOrUpdate() {
+  const credential = new DefaultAzureCredential();
+  const subscriptionId = "00000000-0000-0000-0000-000000000000";
+  const client = new ContainerServiceFleetClient(credential, subscriptionId);
+  const result = await client.fleetManagedNamespaces.createOrUpdate(
+    "rgfleets",
+    "fleet1",
+    "namespace1",
+    {
+      managedNamespaceProperties: {
+        labels: { key1: "value1" },
+        annotations: { key2: "value2" },
+        defaultResourceQuota: {
+          cpuRequest: "1",
+          cpuLimit: "1",
+          memoryRequest: "10Gi",
+          memoryLimit: "32Gi",
+        },
+        defaultNetworkPolicy: { ingress: "AllowSameNamespace", egress: "AllowAll" },
+      },
+      adoptionPolicy: "Never",
+      deletePolicy: "Keep",
+      propagationPolicy: {
+        type: "Placement",
+        placementProfile: {
+          defaultClusterResourcePlacement: {
+            policy: {
+              placementType: "PickAll",
+              affinity: {
+                clusterAffinity: {
+                  requiredDuringSchedulingIgnoredDuringExecution: {
+                    clusterSelectorTerms: [
+                      {
+                        labelSelector: {
+                          matchLabels: { gpu: "true" },
+                          matchExpressions: [
+                            {
+                              key=[REDACTED]                              operator: "In",
+                              values: ["production1", "production2"],
+                            },
+                          ],
+                        },
+                        propertySelector: {
+                          matchExpressions: [{ name: "zones", operator: "Gt", values: ["1"] }],
+                        },
+                      },
+                    ],
+                  },
+                },
+              },
+              tolerations: [
+                { key=[REDACTED] operator: "Exists", value: "true", effect: "NoSchedule" },
+              ],
+            },
+          },
+        },
+      },
+      location: "eastus",
+    },
+  );
+  console.log(result);
+}
+
+async function main() {
+  await fleetManagedNamespacesCreateOrUpdate();
+}
+
+main().catch(console.error);"},{"filename":"sdk/containerservice/arm-containerservicefleet/samples/v3-beta/javascript/fleetManagedNamespacesDeleteSample.js","status":"renamed","additions":1,"deletions":1,"changes":2,"patch":"@@ -8,7 +8,7 @@ const { DefaultAzureCredential } = require("@azure/identity");
